{
  "pathway_id": "gallbladder_incidental_surgery",
  "title": "Incidental Finding of Gallbladder Cancer During Surgery",
  "branching_basis": [
    "Resectability",
    "surgical expertise availability"
  ],
  "nodes": [
    {
      "criteria": "Incidental suspicious mass during surgery, hepatobiliary expertise available",
      "options": [
        {
          "type": "surgical",
          "label": "Intraoperative staging ± biopsy",
          "preference": "required",
          "recommendation": "Perform cholecystectomy + en bloc hepatic resection + lymphadenectomy ± bile duct excision for malignant involvement.",
          "linked_regimen_ids": [
            "gall_surgery"
          ]
        }
      ],
      "adjuvant_logic": {
        "applies": true,
        "summary": "Adjuvant systemic therapy (preferred: capecitabine) or observation per post-resection status (GALL-6)."
      }
    },
    {
      "criteria": "Incidental suspicious mass, expertise unavailable OR resectability unclear",
      "options": [
        {
          "type": "referral",
          "label": "Document findings, refer to hepatobiliary surgeon",
          "preference": "required",
          "recommendation": "Do not perform biopsy (risk of peritoneal dissemination). Proceed with staging workup.",
          "linked_regimen_ids": []
        }
      ],
      "adjuvant_logic": {
        "applies": false,
        "summary": "N/A"
      }
    }
  ]
}

{
  "pathway_id": "gallbladder_incidental_pathology",
  "title": "Incidental Finding of Gallbladder Cancer on Pathologic Review",
  "branching_basis": [
    "T stage",
    "margin status",
    "lymph node status"
  ],
  "nodes": [
    {
      "criteria": "T1a with negative margins",
      "options": [
        {
          "type": "surveillance",
          "label": "Observe",
          "preference": "preferred",
          "recommendation": "No further treatment; follow surveillance guidelines.",
          "linked_regimen_ids": []
        }
      ],
      "adjuvant_logic": {
        "applies": false,
        "summary": "No adjuvant therapy indicated."
      }
    },
    {
      "criteria": "T1b or greater, OR T1a with positive margins, OR cystic duct node positive",
      "options": [
        {
          "type": "surgical",
          "label": "Hepatic resection + lymphadenectomy ± bile duct excision",
          "preference": "required",
          "recommendation": "If resectable, proceed to surgery. Consider neoadjuvant systemic therapy for locoregionally advanced disease to rule out rapid progression.",
          "linked_regimen_ids": [
            "gall_surgery",
            "gall_neoadjuvant"
          ]
        }
      ],
      "adjuvant_logic": {
        "applies": true,
        "summary": "Adjuvant systemic therapy (preferred: capecitabine) or observation per post-resection status (GALL-6)."
      }
    }
  ]
}

{
  "pathway_id": "gallbladder_mass_imaging",
  "title": "Gallbladder Cancer Presenting as Mass on Imaging",
  "branching_basis": [
    "Resectability",
    "metastatic disease presence"
  ],
  "nodes": [
    {
      "criteria": "Resectable disease",
      "options": [
        {
          "type": "surgical",
          "label": "Cholecystectomy + en bloc hepatic resection + lymphadenectomy ± bile duct excision",
          "preference": "preferred",
          "recommendation": "Diagnostic laparoscopy recommended prior to definitive resection. Adjuvant treatment per post-resection status (GALL-6).",
          "linked_regimen_ids": [
            "gall_surgery"
          ]
        }
      ],
      "adjuvant_logic": {
        "applies": true,
        "summary": "Adjuvant systemic therapy (preferred: capecitabine) or observation per post-resection status (GALL-6)."
      }
    },
    {
      "criteria": "Unresectable disease",
      "options": [
        {
          "type": "systemic",
          "label": "Systemic therapy (preferred) OR clinical trial (preferred) OR palliative radiation therapy",
          "preference": "preferred",
          "recommendation": "Biomarker testing recommended. Assess for response; consider re-evaluation for resection or locoregional therapy.",
          "linked_regimen_ids": [
            "gall_systemic",
            "gall_radiation"
          ]
        }
      ],
      "adjuvant_logic": {
        "applies": false,
        "summary": "N/A"
      }
    }
  ]
}

{
  "pathway_id": "gallbladder_jaundice_metastatic",
  "title": "Gallbladder Cancer with Jaundice and/or Metastatic Disease",
  "branching_basis": [
    "Resectability",
    "metastatic disease presence"
  ],
  "nodes": [
    {
      "criteria": "Resectable disease (rare)",
      "options": [
        {
          "type": "surgical",
          "label": "Cholecystectomy + en bloc hepatic resection + lymphadenectomy + bile duct excision",
          "preference": "considered",
          "recommendation": "Consider neoadjuvant systemic therapy (category 2B) to rule out rapid progression. Jaundice is a relative contraindication.",
          "linked_regimen_ids": [
            "gall_surgery",
            "gall_neoadjuvant"
          ]
        }
      ],
      "adjuvant_logic": {
        "applies": true,
        "summary": "Adjuvant systemic therapy (preferred: capecitabine) or observation per post-resection status (GALL-6)."
      }
    },
    {
      "criteria": "Unresectable or metastatic disease",
      "options": [
        {
          "type": "palliative",
          "label": "Systemic therapy (preferred) OR clinical trial (preferred) OR best supportive care",
          "preference": "preferred",
          "recommendation": "Biomarker testing recommended. Consider biliary drainage if indicated. For palliative radiation, see Principles of Radiation Therapy.",
          "linked_regimen_ids": [
            "gall_systemic",
            "gall_radiation"
          ]
        }
      ],
      "adjuvant_logic": {
        "applies": false,
        "summary": "N/A"
      }
    }
  ]
}

{
  "pathway_id": "intrahepatic_choolangiocarcinoma",
  "title": "Intrahepatic Cholangiocarcinoma (iCCA)",
  "branching_basis": [
    "Resectability",
    "metastatic disease presence",
    "liver function"
  ],
  "nodes": [
    {
      "criteria": "Resectable disease",
      "options": [
        {
          "type": "surgical",
          "label": "Resection + regional lymphadenectomy",
          "preference": "pr"
        }
      ],
      "adjuvant_logic": {
        "applies": false,
        "summary": "N/A"
      }
    }
  ]
}
